  ('0305-305', 305, 305, 'lairon', NULL, 9, 1200, 90, 4, FALSE, FALSE, FALSE, 'LAIRON tempers its steel body by drinking highly nutritious mineral springwater until it is bloated. This POKéMON makes its nest close to springs of delicious water.', '{"back_shiny":"https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/back/shiny/305.png","back_female":null,"front_shiny":"https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/shiny/305.png","back_default":"https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/back/305.png","front_female":null,"front_default":"https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/305.png","back_shiny_female":null,"front_shiny_female":null,"official_artwork_shiny":"https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/shiny/305.png","official_artwork_default":"https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/official-artwork/305.png","dream_sprite_front_default":"https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/other/dream-world/305.svg","dream_sprite_front_female":null}'::jsonb),
